import { CreateEventTicket } from '@domain/events';
import { PublicActionPage } from '@domain/publicActionPage';
import clsx from 'clsx';
import { useCallback, useState } from 'react';
import { Button } from 'src/builder/PublicActionPage/components/Button';
import { ChevronDownIcon } from 'src/builder/PublicActionPage/components/icons';
import { Label } from 'src/builder/PublicActionPage/components/Label';
import { AttendeeDetailForm } from './AttendeeDetailForm';

type Attendee = Omit<CreateEventTicket, 'price' | 'addressAttributes'> & { _internal?: string };
type AttendeeDetailProps = {
  actionPage: PublicActionPage;
  attendee: Attendee;
  updateAttendeeDetails: (details: object, id: string) => void;
};

export const AttendeeDetail = ({
  actionPage,
  attendee,
  updateAttendeeDetails,
}: AttendeeDetailProps) => {
  const [showForm, setShowForm] = useState(false);
  const { ticketTypeId } = attendee;

  const ticketName = actionPage?.event?.ticketTypes.find(
    (ticketType) => ticketType.id === ticketTypeId
  )?.name;
  const ticketGroupName = actionPage?.ticketGroups?.find((group) =>
    group?.ticketGroupTicketTypes?.find((ticket) => ticket.ticketTypeId === ticketTypeId)
  )?.name;

  const handleClick = useCallback(() => {
    setShowForm((show) => !show);
  }, []);

  const handleClear = useCallback(() => {
    updateAttendeeDetails(
      {
        currentlyEmployed: '',
        email: '',
        employerName: '',
        firstName: '',
        lastName: '',
        occupation: 'retired',
        phone: '',
      },
      attendee?._internal as string
    );
  }, [attendee, updateAttendeeDetails]);

  const chevronClasses = clsx(
    'transition-common w-[16px] cursor-pointer duration-200',
    showForm ? '-rotate-180' : ''
  );

  return (
    <div className="mb-2">
      <div className="flex items-center justify-between">
        <div className="mb-2 mt-4 flex">
          <Label>Attendee</Label>
          <Label className="ps-3" variant="regular">
            {ticketGroupName ? `${ticketGroupName} - ${ticketName}` : ticketName}
          </Label>
        </div>

        <div className="flex items-center">
          {showForm && (
            <Button
              className="mr-6 !h-auto cursor-pointer !pr-0 pt-2 !text-[13px] no-underline"
              onClick={handleClear}
              variant="link"
            >
              Clear fields
            </Button>
          )}
          <Button
            className="relative top-[3px]"
            icon={<ChevronDownIcon className={chevronClasses} />}
            onClick={handleClick}
            variant="icon"
          />
        </div>
      </div>

      {!showForm ? (
        <div className="animate-fade-in">
          <Button className="w-full" onClick={() => setShowForm(true)} variant="secondary">
            Add attendee details
          </Button>
        </div>
      ) : (
        <div className="animate-scale-in">
          <AttendeeDetailForm
            actionPage={actionPage}
            attendee={attendee}
            updateAttendeeDetails={updateAttendeeDetails}
          />
        </div>
      )}
    </div>
  );
};
